import{_ as d,o as a,c as h,a2 as e}from"./chunks/framework.CW5cCyjm.js";const u=JSON.parse('{"title":"&lt;需求名称&gt; PRD","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/templates/prd.md","filePath":"mango-pmo/templates/prd.md"}'),r={name:"mango-pmo/templates/prd.md"};function l(o,t,i,b,n,c){return a(),h("div",null,[...t[0]||(t[0]=[e('<h1 id="lt-需求名称-gt-prd" tabindex="-1">&lt;需求名称&gt; PRD <a class="header-anchor" href="#lt-需求名称-gt-prd" aria-label="Permalink to &quot;&amp;lt;需求名称&amp;gt; PRD&quot;">​</a></h1><blockquote><p>适用规范：<code>mango-pmo/rules/product/01-prd-template.md</code>。 首先 <code>For AI</code>：让 AI 可理解、可开发、可验收。 其次 <code>For Human</code>：帮助人把需求写成 AI 能理解的无歧义输入，降低 AI 落地偏差。 本文只写业务需求和页面原型。禁止写接口、权限码、数据库、路由、component key、模块归属、初始化方式、测试命令和交付台账。</p></blockquote><h2 id="_0-编写前检查" tabindex="-1">0. 编写前检查 <a class="header-anchor" href="#_0-编写前检查" aria-label="Permalink to &quot;0. 编写前检查&quot;">​</a></h2><h3 id="_0-1-ai-动作判定" tabindex="-1">0.1 AI 动作判定 <a class="header-anchor" href="#_0-1-ai-动作判定" aria-label="Permalink to &quot;0.1 AI 动作判定&quot;">​</a></h3><table tabindex="0"><thead><tr><th>动作</th><th>使用条件</th><th>当前结论</th><th>依据</th></tr></thead><tbody><tr><td>STOP/ASK/WRITE/NEXT</td><td>阻断则 STOP；需业务确认则 ASK；可生成正文则 WRITE；自检全 PASS 且可进设计则 NEXT</td><td></td><td></td></tr></tbody></table><h3 id="_0-2-待确认问题" tabindex="-1">0.2 待确认问题 <a class="header-anchor" href="#_0-2-待确认问题" aria-label="Permalink to &quot;0.2 待确认问题&quot;">​</a></h3><table tabindex="0"><thead><tr><th>顺序</th><th>问题类型</th><th>待确认问题</th><th>影响范围</th><th>是否阻断</th><th>AI动作(STOP/ASK/WRITE)</th><th>用户回答后落点</th></tr></thead><tbody><tr><td>1</td><td>目标用户/关键对象/生命周期/关键流程/业务规则/菜单页面/验收标准/不处理范围</td><td></td><td></td><td>是/否</td><td></td><td></td></tr></tbody></table><h3 id="_0-3-输出顺序" tabindex="-1">0.3 输出顺序 <a class="header-anchor" href="#_0-3-输出顺序" aria-label="Permalink to &quot;0.3 输出顺序&quot;">​</a></h3><p>存在阻断项时，只输出编写前检查和待确认问题；无阻断项时再输出 PRD 正文、自检和进入详细设计判定。</p><h3 id="_0-4-编号规则" tabindex="-1">0.4 编号规则 <a class="header-anchor" href="#_0-4-编号规则" aria-label="Permalink to &quot;0.4 编号规则&quot;">​</a></h3><ul><li>关键对象：<code>&amp;lt;BO-ID&amp;gt;</code>，必须替换为真实稳定编号。</li><li>关键业务流程：<code>&amp;lt;BF-ID&amp;gt;</code>，必须替换为真实稳定编号。</li><li>业务规则：<code>&amp;lt;BR-ID&amp;gt;</code>，必须替换为真实稳定编号。</li><li>页面：<code>&amp;lt;PG-ID&amp;gt;</code>，必须替换为真实稳定编号。</li><li>验收项：<code>&amp;lt;AC-ID&amp;gt;</code>，必须替换为真实稳定编号。</li></ul><h2 id="_1-需求范围" tabindex="-1">1. 需求范围 <a class="header-anchor" href="#_1-需求范围" aria-label="Permalink to &quot;1. 需求范围&quot;">​</a></h2><p>写清本次包含的业务能力、菜单、页面和主要流程。不要写实现方式。</p><h2 id="_2-不处理范围" tabindex="-1">2. 不处理范围 <a class="header-anchor" href="#_2-不处理范围" aria-label="Permalink to &quot;2. 不处理范围&quot;">​</a></h2><p>写清本次不支持的业务场景、不设计的菜单页面、不处理的流程和按钮。</p><h2 id="_3-业务术语" tabindex="-1">3. 业务术语 <a class="header-anchor" href="#_3-业务术语" aria-label="Permalink to &quot;3. 业务术语&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>业务含义</th><th>页面展示名称</th><th>说明</th></tr></thead><tbody><tr><td></td><td></td><td></td><td></td></tr></tbody></table><h2 id="_4-业务用户类型" tabindex="-1">4. 业务用户类型 <a class="header-anchor" href="#_4-业务用户类型" aria-label="Permalink to &quot;4. 业务用户类型&quot;">​</a></h2><p>PRD 不写权限码和授权模型，但必须写清业务用户类型、可见内容、可执行动作、不可执行动作和用户可见原因。</p><table tabindex="0"><thead><tr><th>用户类型</th><th>使用场景</th><th>可见内容</th><th>可执行动作</th><th>不可执行动作</th><th>用户可见原因</th></tr></thead><tbody><tr><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><h2 id="_5-关键对象" tabindex="-1">5. 关键对象 <a class="header-anchor" href="#_5-关键对象" aria-label="Permalink to &quot;5. 关键对象&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对象ID</th><th>对象</th><th>业务含义</th><th>用户可见信息</th><th>主要动作</th><th>生命周期概览</th></tr></thead><tbody><tr><td>&lt;BO-ID&gt;</td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><table tabindex="0"><thead><tr><th>对象ID</th><th>唯一识别口径</th><th>归属口径</th><th>数量/金额/有效期边界</th><th>重复判断口径</th><th>统计口径</th></tr></thead><tbody><tr><td>&lt;BO-ID&gt;</td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><h2 id="_6-对象生命周期与状态口径" tabindex="-1">6. 对象生命周期与状态口径 <a class="header-anchor" href="#_6-对象生命周期与状态口径" aria-label="Permalink to &quot;6. 对象生命周期与状态口径&quot;">​</a></h2><p>只写业务状态和用户可见口径，不写状态字段和技术枚举。</p><table tabindex="0"><thead><tr><th>对象ID</th><th>状态</th><th>业务含义</th><th>进入条件</th><th>退出条件</th><th>可执行动作</th><th>不可执行动作</th><th>用户可见原因</th><th>是否可逆</th><th>触发流程ID</th><th>是否终态</th><th>终态说明</th><th>引用ID</th></tr></thead><tbody><tr><td>&lt;BO-ID&gt;</td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td>是/否</td><td>&lt;BF-ID&gt;</td><td>是/否</td><td></td><td>&lt;BR/PG/AC-ID&gt;</td></tr></tbody></table><h2 id="_7-关键业务流程" tabindex="-1">7. 关键业务流程 <a class="header-anchor" href="#_7-关键业务流程" aria-label="Permalink to &quot;7. 关键业务流程&quot;">​</a></h2><h3 id="_7-x-lt-bf-id-gt-流程-lt-流程名称-gt" tabindex="-1">7.x &lt;BF-ID&gt; 流程：&lt;流程名称&gt; <a class="header-anchor" href="#_7-x-lt-bf-id-gt-流程-lt-流程名称-gt" aria-label="Permalink to &quot;7.x &amp;lt;BF-ID&amp;gt; 流程：&amp;lt;流程名称&amp;gt;&quot;">​</a></h3><h4 id="流程目标" tabindex="-1">流程目标 <a class="header-anchor" href="#流程目标" aria-label="Permalink to &quot;流程目标&quot;">​</a></h4><h4 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h4><h4 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h4><h4 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h4><p>从用户视角描述操作过程，不写系统处理步骤。</p><h4 id="业务规则清单" tabindex="-1">业务规则清单 <a class="header-anchor" href="#业务规则清单" aria-label="Permalink to &quot;业务规则清单&quot;">​</a></h4><h5 id="规则-lt-br-id-gt-lt-规则名称-gt" tabindex="-1">规则 &lt;BR-ID&gt;：&lt;规则名称&gt; <a class="header-anchor" href="#规则-lt-br-id-gt-lt-规则名称-gt" aria-label="Permalink to &quot;规则 &amp;lt;BR-ID&amp;gt;：&amp;lt;规则名称&amp;gt;&quot;">​</a></h5><ul><li>定义：</li><li>适用业务用户类型：</li><li>触发条件：</li><li>判断口径：</li><li>处理方式：</li><li>用户反馈：</li><li>状态变化：</li><li>影响范围：</li><li>例外情况：</li><li>验收标准：</li></ul><h4 id="状态变化" tabindex="-1">状态变化 <a class="header-anchor" href="#状态变化" aria-label="Permalink to &quot;状态变化&quot;">​</a></h4><table tabindex="0"><thead><tr><th>操作前</th><th>操作</th><th>操作后</th></tr></thead><tbody><tr><td></td><td></td><td></td></tr></tbody></table><h4 id="异常与限制" tabindex="-1">异常与限制 <a class="header-anchor" href="#异常与限制" aria-label="Permalink to &quot;异常与限制&quot;">​</a></h4><h4 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h4><h2 id="_8-菜单规划" tabindex="-1">8. 菜单规划 <a class="header-anchor" href="#_8-菜单规划" aria-label="Permalink to &quot;8. 菜单规划&quot;">​</a></h2><p>PRD 只写业务菜单名称、层级、页面用途和按钮可见/可用的业务条件。</p><table tabindex="0"><thead><tr><th>页面ID</th><th>菜单层级</th><th>菜单名称</th><th>菜单类型</th><th>展示顺序</th><th>对应页面</th><th>说明</th></tr></thead><tbody><tr><td>&lt;PG-ID&gt;</td><td></td><td></td><td>目录/页面</td><td></td><td></td><td></td></tr></tbody></table><h2 id="_9-页面总览" tabindex="-1">9. 页面总览 <a class="header-anchor" href="#_9-页面总览" aria-label="Permalink to &quot;9. 页面总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>页面ID</th><th>菜单</th><th>页面名称</th><th>页面类型</th><th>页面用途</th><th>关联关键对象ID</th><th>关联关键流程ID</th></tr></thead><tbody><tr><td>&lt;PG-ID&gt;</td><td></td><td></td><td></td><td></td><td>&lt;BO-ID&gt;</td><td>&lt;BF-ID&gt;</td></tr></tbody></table><h2 id="_10-菜单级页面原型" tabindex="-1">10. 菜单级页面原型 <a class="header-anchor" href="#_10-菜单级页面原型" aria-label="Permalink to &quot;10. 菜单级页面原型&quot;">​</a></h2><h3 id="_10-x-lt-pg-id-gt-lt-菜单名称-页面名称-gt" tabindex="-1">10.x &lt;PG-ID&gt; &lt;菜单名称 / 页面名称&gt; <a class="header-anchor" href="#_10-x-lt-pg-id-gt-lt-菜单名称-页面名称-gt" aria-label="Permalink to &quot;10.x &amp;lt;PG-ID&amp;gt; &amp;lt;菜单名称 / 页面名称&amp;gt;&quot;">​</a></h3><h4 id="页面范围与特性" tabindex="-1">页面范围与特性 <a class="header-anchor" href="#页面范围与特性" aria-label="Permalink to &quot;页面范围与特性&quot;">​</a></h4><h4 id="用户场景" tabindex="-1">用户场景 <a class="header-anchor" href="#用户场景" aria-label="Permalink to &quot;用户场景&quot;">​</a></h4><h4 id="页面布局" tabindex="-1">页面布局 <a class="header-anchor" href="#页面布局" aria-label="Permalink to &quot;页面布局&quot;">​</a></h4><h4 id="搜索区" tabindex="-1">搜索区 <a class="header-anchor" href="#搜索区" aria-label="Permalink to &quot;搜索区&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>业务含义</th><th>控件样式</th><th>业务来源</th><th>选项来源</th><th>联动字段</th><th>默认值</th><th>过滤口径</th><th>是否必填</th><th>说明</th></tr></thead><tbody><tr><td></td><td></td><td></td><td>用户输入/业务字典/关键对象</td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><h4 id="页面功能按钮" tabindex="-1">页面功能按钮 <a class="header-anchor" href="#页面功能按钮" aria-label="Permalink to &quot;页面功能按钮&quot;">​</a></h4><table tabindex="0"><thead><tr><th>按钮</th><th>位置</th><th>显示条件</th><th>点击后交互</th><th>成功反馈</th><th>失败反馈</th><th>关联规则ID</th><th>关联验收ID</th></tr></thead><tbody><tr><td></td><td></td><td></td><td></td><td></td><td></td><td>&lt;BR-ID&gt;</td><td>&lt;AC-ID&gt;</td></tr></tbody></table><h4 id="列表内容" tabindex="-1">列表内容 <a class="header-anchor" href="#列表内容" aria-label="Permalink to &quot;列表内容&quot;">​</a></h4><table tabindex="0"><thead><tr><th>列名</th><th>业务含义</th><th>展示样式</th><th>业务来源</th><th>默认排序</th><th>空值业务含义</th><th>空值展示</th><th>过长处理</th><th>说明</th></tr></thead><tbody><tr><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><h4 id="行功能按钮" tabindex="-1">行功能按钮 <a class="header-anchor" href="#行功能按钮" aria-label="Permalink to &quot;行功能按钮&quot;">​</a></h4><table tabindex="0"><thead><tr><th>按钮</th><th>显示条件</th><th>可点击条件</th><th>点击后交互</th><th>成功反馈</th><th>失败反馈</th><th>关联规则ID</th><th>关联验收ID</th></tr></thead><tbody><tr><td></td><td></td><td></td><td></td><td></td><td></td><td>&lt;BR-ID&gt;</td><td>&lt;AC-ID&gt;</td></tr></tbody></table><h4 id="表单内容" tabindex="-1">表单内容 <a class="header-anchor" href="#表单内容" aria-label="Permalink to &quot;表单内容&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>业务含义</th><th>控件样式</th><th>业务来源</th><th>选项来源</th><th>联动字段</th><th>是否必填</th><th>默认值</th><th>输入限制</th><th>提示文案</th><th>创建可填</th><th>编辑可改</th><th>详情展示</th></tr></thead><tbody><tr><td></td><td></td><td></td><td>用户输入/业务字典/关键对象</td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><h4 id="详情内容" tabindex="-1">详情内容 <a class="header-anchor" href="#详情内容" aria-label="Permalink to &quot;详情内容&quot;">​</a></h4><h4 id="交互流程" tabindex="-1">交互流程 <a class="header-anchor" href="#交互流程" aria-label="Permalink to &quot;交互流程&quot;">​</a></h4><h4 id="状态与反馈" tabindex="-1">状态与反馈 <a class="header-anchor" href="#状态与反馈" aria-label="Permalink to &quot;状态与反馈&quot;">​</a></h4><p>必须覆盖正常态、空态、加载态、失败态、无权限/不可操作态。涉及表单时必须覆盖校验失败、取消、关闭、未保存离开。涉及危险操作时必须覆盖确认、成功、失败和不可逆提示。</p><table tabindex="0"><thead><tr><th>状态类型</th><th>场景</th><th>展示文案</th><th>展示样式</th><th>可见按钮</th><th>可点击按钮</th><th>禁用原因</th></tr></thead><tbody><tr><td>正常/空/加载/失败/不可操作</td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><h4 id="验收引用" tabindex="-1">验收引用 <a class="header-anchor" href="#验收引用" aria-label="Permalink to &quot;验收引用&quot;">​</a></h4><p>页面章节只引用全局验收项，不重复定义验收标准。</p><table tabindex="0"><thead><tr><th>验收ID</th><th>覆盖页面能力</th><th>操作路径</th><th>用户可见断言摘要</th></tr></thead><tbody><tr><td>&lt;AC-ID&gt;</td><td></td><td></td><td></td></tr></tbody></table><h2 id="_11-字典与展示项" tabindex="-1">11. 字典与展示项 <a class="header-anchor" href="#_11-字典与展示项" aria-label="Permalink to &quot;11. 字典与展示项&quot;">​</a></h2><p>只写业务选项和展示文案，不写编码、存储、初始化和技术来源。</p><table tabindex="0"><thead><tr><th>名称</th><th>业务含义</th><th>展示项</th><th>默认项</th><th>适用页面</th><th>说明</th></tr></thead><tbody><tr><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><h2 id="_12-追踪矩阵" tabindex="-1">12. 追踪矩阵 <a class="header-anchor" href="#_12-追踪矩阵" aria-label="Permalink to &quot;12. 追踪矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>来源ID</th><th>来源类型</th><th>覆盖页面ID</th><th>覆盖流程ID</th><th>覆盖规则ID</th><th>验收项ID</th></tr></thead><tbody><tr><td>&lt;BO/BF/BR/PG-ID&gt;</td><td>关键对象/关键流程/业务规则/页面</td><td>&lt;PG-ID&gt;</td><td>&lt;BF-ID&gt;</td><td>&lt;BR-ID&gt;</td><td>&lt;AC-ID&gt;</td></tr></tbody></table><h2 id="_13-验收标准" tabindex="-1">13. 验收标准 <a class="header-anchor" href="#_13-验收标准" aria-label="Permalink to &quot;13. 验收标准&quot;">​</a></h2><p>验收标准只写用户可见结果。成功、失败、禁止、例外和边界都必须有用户可见断言。</p><table tabindex="0"><thead><tr><th>ID</th><th>来源</th><th>验收项</th><th>用户操作</th><th>用户可见结果</th></tr></thead><tbody><tr><td>&lt;AC-ID&gt;</td><td>&lt;BO/BF/BR/PG-ID&gt;</td><td></td><td></td><td></td></tr></tbody></table><h2 id="_14-风险与限制" tabindex="-1">14. 风险与限制 <a class="header-anchor" href="#_14-风险与限制" aria-label="Permalink to &quot;14. 风险与限制&quot;">​</a></h2><table tabindex="0"><thead><tr><th>风险/缺口</th><th>类型</th><th>影响范围</th><th>当前处理</th><th>待确认人</th><th>是否阻断</th></tr></thead><tbody><tr><td></td><td>需求缺口/业务风险/验收限制</td><td></td><td></td><td></td><td>是/否</td></tr></tbody></table><h2 id="_15-进入详细设计判定" tabindex="-1">15. 进入详细设计判定 <a class="header-anchor" href="#_15-进入详细设计判定" aria-label="Permalink to &quot;15. 进入详细设计判定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>检查项</th><th>结果</th><th>证据</th></tr></thead><tbody><tr><td>阻断问题数量</td><td></td><td></td></tr><tr><td>未覆盖 BO/BF/BR/PG/AC 数量</td><td></td><td></td></tr><tr><td>是否出现 PRD 禁止技术内容</td><td>是/否</td><td></td></tr><tr><td>结论</td><td>READY/BLOCKED/EXCEPTION</td><td></td></tr></tbody></table><h2 id="_16-ai-输出自检" tabindex="-1">16. AI 输出自检 <a class="header-anchor" href="#_16-ai-输出自检" aria-label="Permalink to &quot;16. AI 输出自检&quot;">​</a></h2><p>自检结果只能填写 <code>PASS</code>、<code>FAIL</code>、<code>BLOCKED</code> 或 <code>EXCEPTION</code>。任一 <code>FAIL/BLOCKED</code> 时，最终动作只能是 <code>STOP/ASK</code>；<code>EXCEPTION</code> 必须引用用户确认来源；全部 <code>PASS</code> 且进入详细设计判定为 <code>READY</code> 时，最终动作才可为 <code>NEXT</code>。</p><table tabindex="0"><thead><tr><th>检查项</th><th>结果</th><th>说明</th></tr></thead><tbody><tr><td>每个关键对象是否至少关联一个流程、页面或验收项</td><td></td><td></td></tr><tr><td>每个关键流程是否包含规则、状态变化、异常限制和验收标准</td><td></td><td></td></tr><tr><td>每条业务规则是否至少被一个流程、页面或验收项引用</td><td></td><td></td></tr><tr><td>每个页面按钮是否能追溯到关键流程或业务规则</td><td></td><td></td></tr><tr><td>每个验收项是否有明确用户操作和可见结果</td><td></td><td></td></tr><tr><td>是否覆盖正常态、空态、加载态、失败态、不可操作态</td><td></td><td></td></tr><tr><td>PRD 中是否没有接口、权限码、数据库、路由、组件实现和测试命令</td><td></td><td></td></tr></tbody></table>',83)])])}const m=d(r,[["render",l]]);export{u as __pageData,m as default};
